_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = texture(sampler_rand00, vUv).xyz-0.5;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
float dist = 1;
float inten = 1;
ret1 = 0;
int anz = 3;//# layers
float n = 0;

vec2 cntr = vec2(q13,q14); float msin = q11; float mcos = q12; float scale = q15;
vec2 uv_r = (vUv-cntr)*uAspect.xy;
       uv_r = scale*vec2( mcos*uv_r.x - msin*uv_r.y, msin*uv_r.x + mcos*uv_r.y); // rotation
       uv_r = cntr + uv_r*uAspect.zw;
       uv_r = 1.0 - abs( fract( uv_r * 0.5 ) * 2.0 - 1.0 ); // mirror
msin = q17; mcos = q18; scale = q16;
vec2 uv_rr = (uv_r-cntr)*uAspect.xy;
       uv_rr = scale*vec2( mcos*uv_rr.x - msin*uv_rr.y, msin*uv_rr.x + mcos*uv_rr.y); // counter-rotation
       uv_rr = cntr + (uv_rr)*uAspect.zw;
vec2 caleidoscope_uv = uv_rr;
ret = GetBlur3(uv_rr) + (GetPixel(uv_rr)-GetBlur2(uv_rr))*2.4 - 0.1; // nice edge enhancing, also makes an aura

vUv -= 0.5;
vUv *= uAspect.xy;
while (n <= anz) {
    uv2 = vUv+ret;
    dist = 1-fract(1.0/anz*n+q30); //evtl sqrt !
    inten =  dist*(1-dist)*3;
    vec2 uv3 =  fract(1.5*uv2*dist+q15+vec2(q18+dist/3,0));
    neu = GetPixel(uv3) -.7*GetBlur3(uv3*1.05);
    ret1 = max(ret1,neu*inten);
n++;
}
rs2 = .3*sin(vUv*4+q15) - lum(ret1);//sub lum(ret1) pretty much is the light distortion effect
float dots = (.05/length(rs2))*q26*.5;
ret = (q1+.5)*ret1 + dots*vec3 (q8,q9,q10) ;

  fragColor = ret;
}
